/**
 * SECTION 1: Admin Pages - Functional Tests
 * Test các admin pages với functional checks chi tiết
 */
test.describe('Admin Pages - Functional Coverage', () => {
  const ADMIN_PAGES = [
    { path: '/admin/inventory.html', name: 'Inventory Management', expectedElements: ['inventory', 'stock', 'product'] },
    { path: '/admin/loyalty.html', name: 'Loyalty Program', expectedElements: ['loyalty', 'points', 'rewards'] },
    { path: '/admin/menu.html', name: 'Menu Manager', expectedElements: ['menu', 'items', 'category'] },
    { path: '/admin/notifications.html', name: 'Notifications', expectedElements: ['notification', 'alert', 'message'] },
    { path: '/admin/pos.html', name: 'POS System', expectedElements: ['pos', 'sale', 'checkout'] },
    { path: '/admin/quality.html', name: 'Quality Control', expectedElements: ['quality', 'control', 'check'] },
    { path: '/admin/raas-overview.html', name: 'RaaS Overview', expectedElements: ['raas', 'overview', 'dashboard'] },
    { path: '/admin/roiaas-admin.html', name: 'ROIaaS Admin', expectedElements: ['roi', 'analytics', 'dashboard'] },
    { path: '/admin/shifts.html', name: 'Shifts Management', expectedElements: ['shift', 'schedule', 'employee'] },
    { path: '/admin/suppliers.html', name: 'Suppliers', expectedElements: ['supplier', 'vendor', 'contact'] },
  ];

  for (const page of ADMIN_PAGES) {
    test.describe(`${page.name}`, () => {
      test('loads without critical errors', async ({ page: p }) => {
        const errors: string[] = [];
        p.on('pageerror', (error) => {
          if (error.message.includes('supabase') || error.message.includes('__ENV__')) return;
          if (/is not defined/.test(error.message) && /createDemo|Auth|mekongAgents/.test(error.message)) return;
          if (error.message.includes('CustomElementRegistry')) return;
          errors.push(error.message);
        });

        const response = await p.goto(page.path, { waitUntil: 'domcontentloaded', timeout: 15000 });
        expect(response?.status()).toBe(200);
        expect(errors.length).toBeLessThanOrEqual(0);
      });

      test('has valid HTML structure', async ({ page: p }) => {
        await p.goto(page.path, { waitUntil: 'domcontentloaded', timeout: 15000 });

        // Check DOCTYPE
        const hasDoctype = await p.evaluate(() => document.firstChild?.nodeType === 10);
        expect(hasDoctype).toBe(true);

        // Check html lang
        const htmlLang = await p.getAttribute('html', 'lang');
        expect(htmlLang).toBeTruthy();

        // Check title
        const title = await p.title();
        expect(title.length).toBeGreaterThan(0);
        expect(title.toLowerCase()).toContain(page.name.toLowerCase().split(' ')[0]);
      });

      test('has required meta tags', async ({ page: p }) => {
        await p.goto(page.path, { waitUntil: 'domcontentloaded', timeout: 15000 });

        // Viewport
        const viewport = await p.getAttribute('meta[name="viewport"]', 'content');
        expect(viewport).toBeTruthy();

        // Charset
        const charset = await p.querySelector('meta[charset]');
        expect(charset).toBeTruthy();

        // Description (optional but recommended)
        const description = await p.getAttribute('meta[name="description"]', 'content');
        // Not failing if missing, just logging
        if (!description) {
          console.log(`Missing description on ${page.path}`);
        }
      });

      test('is responsive on mobile', async ({ page: p }) => {
        await p.setViewportSize({ width: 375, height: 812 });
        const response = await p.goto(page.path, { waitUntil: 'domcontentloaded', timeout: 15000 });
        expect(response?.status()).toBe(200);
      });

      test('has main landmark for accessibility', async ({ page: p }) => {
        await p.goto(page.path, { waitUntil: 'domcontentloaded', timeout: 15000 });
        const hasMain = await p.evaluate(() => document.querySelector('main, [role="main"]') !== null);
        expect(hasMain).toBe(true);
      });
    });
  }
});

