/**
 * SECTION 7: Link Validation - Comprehensive Check
 */
test.describe('Link Validation - All Pages', () => {
  const PAGES_TO_CHECK = [
    '/admin/dashboard.html',
    '/admin/agents.html',
    '/admin/campaigns.html',
    '/portal/dashboard.html',
    '/affiliate/dashboard.html',
  ];

  for (const pagePath of PAGES_TO_CHECK) {
    test(`no broken links on ${pagePath}`, async ({ page }) => {
      await page.goto(pagePath, { waitUntil: 'domcontentloaded' });

      const links = await page.locator('a[href]').all();
      const brokenLinks: string[] = [];

      for (const link of links.slice(0, 20)) { // Check first 20 links
        const href = await link.getAttribute('href');
        if (href && !href.startsWith('#') && !href.startsWith('javascript:') && !href.startsWith('mailto:')) {
          // Internal links only
          if (href.startsWith('/') || !href.includes('://')) {
            try {
              const response = await page.request.get(href);
              if (response.status() >= 400) {
                brokenLinks.push(`${href} -> ${response.status()}`);
              }
            } catch {
              // Ignore network errors
            }
          }
        }
      }

      expect(brokenLinks.length, `Broken links: ${brokenLinks.join(', ')}`).toBeLessThanOrEqual(3);
    });
  }
});

/**
 * SECTION 8: Performance - Page Load Time
 */
test.describe('Performance - Page Load Time', () => {
  const KEY_PAGES = [
    '/admin/dashboard.html',
    '/portal/dashboard.html',
    '/index.html',
  ];

  for (const pagePath of KEY_PAGES) {
    test(`${pagePath} loads within performance budget`, async ({ page }) => {
      const startTime = Date.now();
      const response = await page.goto(pagePath, { waitUntil: 'domcontentloaded' });
      const loadTime = Date.now() - startTime;

      expect(response?.status()).toBe(200);
      expect(loadTime).toBeLessThan(5000); // 5 second budget
    });
  }
});
